/**
 * Theme type definitions shared across packages.
 * Keep this schema-only — no runtime logic.
 */

/** Identifier for one of the built-in editor color themes. */
export type BuiltInThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/**
 * CSS color value strings for every themed surface in the app.
 * All values must be valid standalone CSS color expressions
 * (e.g. `#09090b`, `oklch(0.588 0.217 264)`, `rgba(255,255,255,0.06)`)
 * — no references to other CSS custom properties.
 */
export interface ThemeColors {
  // ── Core palette ────────────────────────────────────────────
  background: string;
  foreground: string;
  primary: string;
  primaryForeground: string;
  card: string;
  cardForeground: string;
  border: string;
  muted: string;
  mutedForeground: string;
  accent: string;
  accentForeground: string;
  ring: string;

  // ── Sidebar surface ──────────────────────────────────────────
  sidebarBackground: string;
  sidebarForeground: string;
  sidebarBorder: string;

  // ── Editor surface ───────────────────────────────────────────
  editorBackground: string;
  editorForeground: string;

  // ── Terminal surface ─────────────────────────────────────────
  terminalBackground: string;
  terminalForeground: string;

  // ── Status bar surface ───────────────────────────────────────
  statusBarBackground: string;
  statusBarForeground: string;
}

/** A fully-specified built-in color theme. */
export interface BuiltInTheme {
  readonly id: BuiltInThemeId;
  readonly label: string;
  readonly description: string;
  /** Whether the theme reads as a dark or light visual scheme. */
  readonly colorScheme: "light" | "dark";
  readonly colors: ThemeColors;
}

