import type { BuiltInTheme, BuiltInThemeId, ThemeColors } from "@t3tools/contracts";

// ─── Built-in theme definitions ───────────────────────────────────────────────

export const BUILT_IN_THEMES: readonly BuiltInTheme[] = [
  {
    id: "t3-dark",
    label: "T3 Dark",
    description: "Default dark theme with violet accents.",
    colorScheme: "dark",
    colors: {
      background: "#09090b",
      foreground: "#f5f5f5",
      primary: "oklch(0.588 0.217 264)",
      primaryForeground: "#ffffff",
      card: "#111113",
      cardForeground: "#f5f5f5",
      border: "rgba(255, 255, 255, 0.06)",
      muted: "rgba(255, 255, 255, 0.04)",
      mutedForeground: "#a3a3a3",
      accent: "rgba(255, 255, 255, 0.04)",
      accentForeground: "#f5f5f5",
      ring: "oklch(0.588 0.217 264)",
      sidebarBackground: "#0f0f12",
      sidebarForeground: "#d4d4d8",
      sidebarBorder: "rgba(255, 255, 255, 0.05)",
      editorBackground: "#09090b",
      editorForeground: "#f5f5f5",
      terminalBackground: "#09090b",
      terminalForeground: "#e4e4e7",
      statusBarBackground: "#1a1a22",
      statusBarForeground: "#71717a",
    },
  },
  {
    id: "t3-light",
    label: "T3 Light",
    description: "Clean light theme with violet accents.",
    colorScheme: "light",
    colors: {
      background: "#ffffff",
      foreground: "#262626",
      primary: "oklch(0.488 0.217 264)",
      primaryForeground: "#ffffff",
      card: "#ffffff",
      cardForeground: "#262626",
      border: "rgba(0, 0, 0, 0.08)",
      muted: "rgba(0, 0, 0, 0.04)",
      mutedForeground: "#737373",
      accent: "rgba(0, 0, 0, 0.04)",
      accentForeground: "#262626",
      ring: "oklch(0.488 0.217 264)",
      sidebarBackground: "#fafafa",
      sidebarForeground: "#404040",
      sidebarBorder: "rgba(0, 0, 0, 0.06)",
      editorBackground: "#ffffff",
      editorForeground: "#262626",
      terminalBackground: "#f8f8f8",
      terminalForeground: "#262626",
      statusBarBackground: "#f0f0f5",
      statusBarForeground: "#737373",
    },
  },
  {
    id: "t3-midnight",
    label: "T3 Midnight",
    description: "Deep blue-black dark theme with cyan accents.",
    colorScheme: "dark",
    colors: {
      background: "#0b0e1a",
      foreground: "#e2e8f0",
      primary: "oklch(0.65 0.18 230)",
      primaryForeground: "#ffffff",
      card: "#0f1424",
      cardForeground: "#e2e8f0",
      border: "rgba(148, 163, 184, 0.10)",
      muted: "rgba(148, 163, 184, 0.06)",
      mutedForeground: "#64748b",
      accent: "rgba(148, 163, 184, 0.06)",
      accentForeground: "#e2e8f0",
      ring: "oklch(0.65 0.18 230)",
      sidebarBackground: "#080c16",
      sidebarForeground: "#cbd5e1",
      sidebarBorder: "rgba(148, 163, 184, 0.08)",
      editorBackground: "#0b0e1a",
      editorForeground: "#e2e8f0",
      terminalBackground: "#080c16",
      terminalForeground: "#e2e8f0",
      statusBarBackground: "#0d1228",
      statusBarForeground: "#475569",
    },
  },
] as const;

export const DEFAULT_COLOR_THEME_ID: BuiltInThemeId = "t3-dark";

// ─── Lookup helpers ────────────────────────────────────────────────────────────

export function getBuiltInTheme(id: BuiltInThemeId): BuiltInTheme {
  const theme = BUILT_IN_THEMES.find((t) => t.id === id);
  if (!theme) throw new Error(`Unknown built-in theme: "${id}"`);
  return theme;
}

/** Returns true if `raw` is a valid BuiltInThemeId. */
export function isBuiltInThemeId(raw: string): raw is BuiltInThemeId {
  return BUILT_IN_THEMES.some((t) => t.id === raw);
}

// ─── CSS custom-property application ──────────────────────────────────────────

/**
 * Maps each ThemeColors key to the CSS custom property it controls.
 * Surface-specific properties (sidebar, editor, terminal, status-bar) are
 * new additions; the rest override the existing base palette vars.
 */
const COLORS_TO_CSS_VARS: Readonly<Record<keyof ThemeColors, string>> = {
  // Core palette (existing vars)
  background: "--background",
  foreground: "--foreground",
  primary: "--primary",
  primaryForeground: "--primary-foreground",
  card: "--card",
  cardForeground: "--card-foreground",
  border: "--border",
  muted: "--muted",
  mutedForeground: "--muted-foreground",
  accent: "--accent",
  accentForeground: "--accent-foreground",
  ring: "--ring",
  // Sidebar surface (new)
  sidebarBackground: "--sidebar-background",
  sidebarForeground: "--sidebar-foreground",
  sidebarBorder: "--sidebar-border",
  // Editor surface (new)
  editorBackground: "--editor-background",
  editorForeground: "--editor-foreground",
  // Terminal surface (new)
  terminalBackground: "--terminal-background",
  terminalForeground: "--terminal-foreground",
  // Status-bar surface (new)
  statusBarBackground: "--status-bar-background",
  statusBarForeground: "--status-bar-foreground",
};

/**
 * Applies a built-in theme's colors to `document.documentElement` as inline
 * CSS custom properties. Inline styles win over stylesheet rules, so this
 * cleanly overrides both the `:root` defaults and the `.dark` variant.
 *
 * Also derives a few implicit vars (popover, secondary, input) from the core
 * palette so all existing components stay consistent.
 */
export function applyColorThemeVars(id: BuiltInThemeId): void {
  const theme = getBuiltInTheme(id);
  const { colors } = theme;
  const root = document.documentElement;
  const set = (prop: string, value: string) => root.style.setProperty(prop, value);

  // Apply every ThemeColors entry
  for (const [key, cssVar] of Object.entries(COLORS_TO_CSS_VARS) as Array<
    [keyof ThemeColors, string]
  >) {
    set(cssVar, colors[key]);
  }

  // Derived vars — keep existing components consistent without adding them to
  // ThemeColors (they are implied by the core palette).
  set("--popover", colors.card);
  set("--popover-foreground", colors.cardForeground);
  set("--secondary", colors.muted);
  set("--secondary-foreground", colors.mutedForeground);

  // CSS color-scheme hint for browser chrome (scrollbars, form controls, etc.)
  set("color-scheme", theme.colorScheme);
}

