  const theme = BUILT_IN_THEMES.find((t) => t.id === id);
  if (!theme) throw new Error(`Unknown built-in theme: "${id}"`);
  return theme;
}

/** Returns true if `raw` is a valid BuiltInThemeId. */
export function isBuiltInThemeId(raw: string): raw is BuiltInThemeId {
  return BUILT_IN_THEMES.some((t) => t.id === raw);
}

// ─── CSS custom-property application ──────────────────────────────────────────

/**
 * Maps each ThemeColors key to the CSS custom property it controls.
 * Surface-specific properties (sidebar, editor, terminal, status-bar) are
 * new additions; the rest override the existing base palette vars.
 */
const COLORS_TO_CSS_VARS: Readonly<Record<keyof ThemeColors, string>> = {
  // Core palette (existing vars)
  background: "--background",
  foreground: "--foreground",
  primary: "--primary",
  primaryForeground: "--primary-foreground",
  card: "--card",
  cardForeground: "--card-foreground",
  border: "--border",
  muted: "--muted",
  mutedForeground: "--muted-foreground",
  accent: "--accent",
  accentForeground: "--accent-foreground",
  ring: "--ring",
  // Sidebar surface (new)
  sidebarBackground: "--sidebar-background",
  sidebarForeground: "--sidebar-foreground",
  sidebarBorder: "--sidebar-border",
  // Editor surface (new)
  editorBackground: "--editor-background",
  editorForeground: "--editor-foreground",
  // Terminal surface (new)
  terminalBackground: "--terminal-background",
  terminalForeground: "--terminal-foreground",
  // Status-bar surface (new)
  statusBarBackground: "--status-bar-background",
  statusBarForeground: "--status-bar-foreground",
};

/**
 * Applies a built-in theme's colors to `document.documentElement` as inline
 * CSS custom properties. Inline styles win over stylesheet rules, so this
 * cleanly overrides both the `:root` defaults and the `.dark` variant.
 *
 * Also derives a few implicit vars (popover, secondary, input) from the core
 * palette so all existing components stay consistent.
 */
export function applyColorThemeVars(id: BuiltInThemeId): void {
  const theme = getBuiltInTheme(id);
  const { colors } = theme;
  const root = document.documentElement;
  const set = (prop: string, value: string) => root.style.setProperty(prop, value);

  // Apply every ThemeColors entry
  for (const [key, cssVar] of Object.entries(COLORS_TO_CSS_VARS) as Array<
    [keyof ThemeColors, string]
  >) {
    set(cssVar, colors[key]);
  }

  // Derived vars — keep existing components consistent without adding them to
  // ThemeColors (they are implied by the core palette).
  set("--popover", colors.card);
  set("--popover-foreground", colors.cardForeground);
  set("--secondary", colors.muted);
  set("--secondary-foreground", colors.mutedForeground);

  // CSS color-scheme hint for browser chrome (scrollbars, form controls, etc.)
  set("color-scheme", theme.colorScheme);
}

