import { useCallback, useEffect, useSyncExternalStore } from "react";
import type { BuiltInThemeId } from "@t3tools/contracts";
import {
  applyColorThemeVars,
  DEFAULT_COLOR_THEME_ID,
  getBuiltInTheme,
  isBuiltInThemeId,
} from "../themes";

// ─── Dark / light / system mode ───────────────────────────────────────────────

type Theme = "light" | "dark" | "system";
type ThemeSnapshot = {
  theme: Theme;
  systemDark: boolean;
};

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStored(): Theme {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const isDark = theme === "dark" || (theme === "system" && getSystemDark());
  document.documentElement.classList.toggle("dark", isDark);
  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

function getSnapshot(): ThemeSnapshot {
  const theme = getStored();
  const systemDark = theme === "system" ? getSystemDark() : false;

  if (lastSnapshot && lastSnapshot.theme === theme && lastSnapshot.systemDark === systemDark) {
    return lastSnapshot;
  }

  lastSnapshot = { theme, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ─── Color theme (named built-in themes) ──────────────────────────────────────

const COLOR_THEME_STORAGE_KEY = "t3code:color-theme";

let colorThemeListeners: Array<() => void> = [];
let lastColorTheme: BuiltInThemeId | null = null;

function emitColorThemeChange() {
  for (const listener of colorThemeListeners) listener();
}

/**
 * Returns the stored color theme, falling back gracefully:
 * - If no color theme is stored, migrate from the old light/dark preference
 *   so users who had light mode see t3-light, everyone else gets t3-dark.
 */
function getStoredColorTheme(): BuiltInThemeId {
  const raw = localStorage.getItem(COLOR_THEME_STORAGE_KEY);
  if (raw !== null && isBuiltInThemeId(raw)) return raw;

  // Migration: map legacy light preference → t3-light, everything else → t3-dark
  const oldPref = localStorage.getItem(STORAGE_KEY);
  return oldPref === "light" ? "t3-light" : DEFAULT_COLOR_THEME_ID;
}

function getColorThemeSnapshot(): BuiltInThemeId {
  const theme = getStoredColorTheme();
  if (lastColorTheme === theme) return lastColorTheme;
  lastColorTheme = theme;
  return theme;
}

function subscribeColorTheme(listener: () => void): () => void {
  colorThemeListeners.push(listener);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === COLOR_THEME_STORAGE_KEY) {
      applyColorThemeVars(getStoredColorTheme());
      emitColorThemeChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    colorThemeListeners = colorThemeListeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ─── Initial application (runs once at module load to prevent flash) ───────────

applyTheme(getStored());
applyColorThemeVars(getStoredColorTheme());

// ─── Hook ─────────────────────────────────────────────────────────────────────

export function useTheme() {
  // Dark / light / system snapshot
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = snapshot.theme;
  const resolvedTheme: "light" | "dark" =
    theme === "system" ? (snapshot.systemDark ? "dark" : "light") : theme;

  // Color theme snapshot
  const colorTheme = useSyncExternalStore(subscribeColorTheme, getColorThemeSnapshot);

  /** Switch between system / light / dark mode. */
  const setTheme = useCallback((next: Theme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  /**
   * Switch to a named built-in theme.
   * - Persists the selection to localStorage.
   * - Applies CSS custom properties immediately (no flash).
   * - Syncs the dark/light class so existing components stay consistent.
   */
  const setColorTheme = useCallback((id: BuiltInThemeId) => {
    const builtIn = getBuiltInTheme(id);

    // Sync the dark/light class and legacy preference
    const newMode = builtIn.colorScheme; // "light" | "dark"
    localStorage.setItem(STORAGE_KEY, newMode);
    applyTheme(newMode, true);

    // Apply color custom properties
    applyColorThemeVars(id);

    // Persist the color theme selection
    localStorage.setItem(COLOR_THEME_STORAGE_KEY, id);

    // Notify all subscribers
    emitChange();
    emitColorThemeChange();
  }, []);

  // Keep the dark class in sync on mount / external changes
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, resolvedTheme, colorTheme, setColorTheme } as const;
}

