import { useEffect, type ReactNode } from "react";
import { useTheme } from "~/hooks/useTheme";
import { applyColorThemeVars } from "~/themes";

interface ThemeProviderProps {
  children: ReactNode;
}

/**
 * Applies the active color theme's CSS custom properties to
 * `document.documentElement` whenever the selection changes.
 *
 * CSS vars are also applied at module-load time inside `useTheme.ts` to
 * prevent a flash of unstyled content. This component handles subsequent
 * React-driven updates (e.g. the user switching themes in settings).
 *
 * Place this component high in the tree — ideally as the outermost wrapper
 * in the root layout — so every descendant sees the correct CSS vars.
 */
export function ThemeProvider({ children }: ThemeProviderProps) {
  const { colorTheme } = useTheme();

  useEffect(() => {
    applyColorThemeVars(colorTheme);
  }, [colorTheme]);

  return <>{children}</>;
}

