import { useTheme } from "~/hooks/useTheme";
import { BUILT_IN_THEMES } from "~/themes";

/**
 * A grid of visual theme cards with preview swatches.
 * Each card renders a miniature app layout using the theme's actual colors
 * so users can see exactly how the UI will look before selecting.
 */
export function ThemeSelector() {
  const { colorTheme, setColorTheme } = useTheme();

  return (
    <div
      className="grid grid-cols-1 gap-3 sm:grid-cols-3"
      role="radiogroup"
      aria-label="Color theme"
    >
      {BUILT_IN_THEMES.map((theme) => {
        const isSelected = colorTheme === theme.id;
        const { colors } = theme;

        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={isSelected}
            onClick={() => setColorTheme(theme.id)}
            className={[
              "group relative flex flex-col overflow-hidden rounded-xl border text-left transition-all",
              "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
              isSelected
                ? "border-primary/60 ring-1 ring-primary/30"
                : "border-border hover:border-border/80 hover:shadow-sm",
            ].join(" ")}
          >
            {/* ── Preview swatch ─────────────────────────────────── */}
            <div
              className="relative flex h-[72px] w-full overflow-hidden"
              style={{ backgroundColor: colors.editorBackground }}
              aria-hidden="true"
            >
              {/* Sidebar strip */}
              <div
                className="flex w-9 shrink-0 flex-col items-center gap-2 px-1.5 pt-2"
                style={{ backgroundColor: colors.sidebarBackground }}
              >
                {/* Logo / icon placeholder */}
                <div
                  className="h-3 w-3 rounded"
                  style={{ backgroundColor: colors.primary }}
                />
                {/* Nav items */}
                <div
                  className="h-1 w-5 rounded-full"
                  style={{ backgroundColor: colors.sidebarForeground, opacity: 0.35 }}
                />
                <div
                  className="h-1 w-5 rounded-full"
                  style={{ backgroundColor: colors.sidebarForeground, opacity: 0.25 }}
                />
                <div
                  className="h-1 w-5 rounded-full"
                  style={{ backgroundColor: colors.sidebarForeground, opacity: 0.18 }}
                />
                <div
                  className="h-1 w-3 rounded-full"
                  style={{ backgroundColor: colors.sidebarForeground, opacity: 0.12 }}
                />
              </div>

              {/* Editor / chat area */}
              <div className="flex flex-1 flex-col">
                {/* Fake text lines */}
                <div className="flex flex-1 flex-col justify-center gap-2 px-2.5 py-2">
                  <div
                    className="h-1 rounded-full"
                    style={{
                      width: "72%",
                      backgroundColor: colors.editorForeground,
                      opacity: 0.28,
                    }}
                  />
                  <div
                    className="h-1 rounded-full"
                    style={{
                      width: "55%",
                      backgroundColor: colors.editorForeground,
                      opacity: 0.18,
                    }}
                  />
                  <div
                    className="h-1 rounded-full"
                    style={{
                      width: "82%",
                      backgroundColor: colors.editorForeground,
                      opacity: 0.22,
                    }}
                  />
                  <div
                    className="h-1 rounded-full"
                    style={{
                      width: "40%",
                      backgroundColor: colors.primary,
                      opacity: 0.45,
                    }}
                  />
                </div>

                {/* Status bar */}
                <div
                  className="h-3 w-full shrink-0"
                  style={{ backgroundColor: colors.statusBarBackground }}
                />
              </div>

              {/* Accent bar along the top edge */}
              <div
                className="absolute inset-x-0 top-0 h-[2px]"
                style={{ backgroundColor: colors.primary }}
              />
            </div>

            {/* ── Label ──────────────────────────────────────────── */}
            <div
              className="flex items-start justify-between gap-2 px-3 py-2"
              style={{ backgroundColor: colors.card }}
            >
              <div>
                <p
                  className="text-xs font-semibold leading-tight"
                  style={{ color: colors.foreground }}
                >
                  {theme.label}
                </p>
                <p className="mt-0.5 text-[10px] leading-tight" style={{ color: colors.mutedForeground }}>
                  {theme.description}
                </p>
              </div>

              {isSelected ? (
                <span
                  className="shrink-0 rounded px-1.5 py-0.5 text-[9px] font-semibold uppercase tracking-wider"
                  style={{
                    backgroundColor: colors.primary + "22",
                    color: colors.primary,
                  }}
                >
                  Active
                </span>
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

